package com.melancholicbastard.handyasr.data.decode

import com.melancholicbastard.handyasr.domain.decode.DecodeRepository
import okhttp3.MediaType.Companion.toMediaTypeOrNull
import okhttp3.MultipartBody
import okhttp3.RequestBody.Companion.asRequestBody
import java.io.File
import java.io.IOException

class RetrofitDecodeRepository(
    private val decodeApi: DecodeApi
) : DecodeRepository {

    override suspend fun decodeAudio(file: File): String {
        if (!file.exists()) {
            throw IOException("Audio file does not exist: ${file.absolutePath}")
        }

        val requestBody = file.asRequestBody("audio/wav".toMediaTypeOrNull())
        val filePart = MultipartBody.Part.createFormData("file", file.name, requestBody)

        val response = decodeApi.decode(filePart)
        if (!response.isSuccessful) {
            throw IOException("Decode request failed with code ${response.code()}")
        }

        val body = response.body()?.string()?.trim().orEmpty()
        if (body.isBlank()) {
            throw IOException("Decode response is empty")
        }

        return extractText(body)
    }

    private fun extractText(rawBody: String): String {
        val textRegex = "\"text\"\\s*:\\s*\"(.*?)\"".toRegex()
        val textMatch = textRegex.find(rawBody)
        return textMatch?.groupValues?.get(1)
            ?.replace("\\n", "\n")
            ?.replace("\\\"", "\"")
            ?.trim()
            ?.ifBlank { rawBody }
            ?: rawBody
    }
}

package com.melancholicbastard.handyasr.presentation

import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import com.melancholicbastard.handyasr.presentation.screen.HistoryScreen
import com.melancholicbastard.handyasr.presentation.screen.RecorderScreen
import com.melancholicbastard.handyasr.presentation.screen.Screen
import com.melancholicbastard.handyasr.presentation.screen.SettingsScreen

@Composable
fun AppNavGraph(
    navController: NavHostController,
    modifier: Modifier = Modifier,
    startDestination: String = Screen.Recorder.route
) {
    NavHost(
        navController = navController,
        startDestination = startDestination,
        modifier = modifier
    ) {
        composable(Screen.Recorder.route) {
            RecorderScreen()
        }
        composable(Screen.History.route) {
            HistoryScreen()
        }
        composable(Screen.Settings.route) {
            SettingsScreen()
        }
    }
}

package com.melancholicbastard.handyasr.presentation

import androidx.activity.compose.BackHandler
import androidx.compose.runtime.Composable
import androidx.navigation.NavHostController

/**
 * Centralized back button handler for navigation logic.
 *
 * @param navController Nav controller used for navigation operations
 * @param startRoute route of the start destination (e.g. Screen.Recorder.route)
 * @param onExit lambda that will be invoked when there's nothing to pop and current == startRoute
 */
@Composable
fun NavBackHandler(
    navController: NavHostController,
    startRoute: String,
    onExit: () -> Unit
) {
    BackHandler {
        val currentRoute = navController.currentBackStackEntry?.destination?.route
        val hasPrevious = navController.previousBackStackEntry != null

        if (hasPrevious) {
            navController.popBackStack()
        } else {
            if (currentRoute != null && currentRoute != startRoute) {
                navController.navigate(startRoute) {
                    popUpTo(startRoute) { inclusive = true }
                    launchSingleTop = true
                }
            } else {
                onExit()
            }
        }
    }
}
